def compute_score() -> tuple[str, float]:
    # Check if slide 7 exists and has the exact title "Summary of Accounting Terms"
    slide_7 = None

    # Look for slide 7 in added slides
    for slide in ppt_diff.added_slides:
        if slide.slide_number == 7:
            slide_7 = slide
            break

    # If not found in added slides, check modified slides
    if not slide_7:
        for slide, _ in ppt_diff.modified_slides:
            if slide.slide_number == 7:
                slide_7 = slide
                break

    if not slide_7:
        return ("Slide 7 not found.", 0.0)

    title = (slide_7.title or "").strip()
    expected = "Summary of Accounting Terms"

    # Check for exact match only
    if title == expected:
        return ("Slide 7 has the exact title 'Summary of Accounting Terms'.", 1.0)
    else:
        return (f"Slide 7 title is '{title}', expected exactly '{expected}'.", 0.0)

def compute_score() -> tuple[str, float]:
    # Check that exactly one slide was added and no slides were removed
    added_count = len(ppt_diff.added_slides)
    removed_count = len(ppt_diff.removed_slides)
    modified_count = len(ppt_diff.modified_slides)

    # The ideal case: exactly one slide added, nothing else changed
    if added_count == 1 and removed_count == 0 and modified_count <= 1:
        return ("Exactly one slide was added with no other changes.", 1.0)

    # If the right number of slides were added but there are more changes
    if added_count == 1 and removed_count == 0:
        return (f"One slide added but {modified_count} slides were modified.", 0.7)

    # Build error message for other cases
    details = []
    if added_count != 1:
        details.append(f"{added_count} slides added (expected 1)")
    if removed_count > 0:
        details.append(f"{removed_count} slides removed")
    if modified_count > 0:
        details.append(f"{modified_count} slides modified")

    return ("; ".join(details), 0.0)
